const policy = [
    {
        id: 1,
        title: 'Privacy',
        description:
          'At Next Stop, we respect your privacy and are committed to safeguarding your personal information. We only collect essential data needed to improve your experience, such as your email for account creation. We never share your data with third parties without your consent, and you have full control over your account and the visibility of your content.',
    },
    {
        id: 2,
        title: 'Security',
        description:
          'Next Stop prioritizes the safety of our user\'s data. We use industry-standard encryption, including JWT-based authentication, to protect user information and prevent unauthorized access. Access control is enforced at all levels to ensure only authorized users can modify data. Regular security audits and vulnerability assessments are conducted to strengthen our defenses against potential threats.',

    },
    {
        id: 3,
        title: 'Copyright',
        description:
          'Next Stop is dedicated to respecting intellectual property rights. Users are responsible for ensuring that all uploaded content, including images and descriptions, complies with copyright laws. For any copyright infringement concerns, please contact us to initiate a takedown process in accordance with the DMCA.',
    },
  ]

  export default function PolicyPage() {
    return (
      <div className="bg-white py-24 sm:py-32">
        <div className="mx-auto max-w-4xl px-6 lg:px-8">
          <div className="mx-auto max-w-full lg:mx-0">
            <h2 className="text-pretty text-4xl font-semibold tracking-tight text-gray-900 sm:text-5xl">Read our policies</h2>
            <p className="mt-2 text-lg text-gray-600">Take a look at our policies regarding privacy, security, and copyright.</p>
          </div>
          <div className="mx-auto mt-10 grid max-w-full grid-cols-1 gap-x-8 gap-y-16 border-t border-gray-200 pt-10 sm:mt-16 sm:pt-16 lg:grid-cols-3">
              {policies.map((policy) => (
                  <article key={policy.id} className="flex flex-col items-start justify-between">
                  <div className="group relative">
                      <h3 className="mt-3 text-lg font-semibold text-gray-900 group-hover:text-gray-600">
                          {policy.title}
                      </h3>
                      <p className="mt-5 text-sm text-gray-600">{policy.description}</p>
                  </div>
                  </article>
              ))}
          </div>
        </div>
      </div>
    )
}
